const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Normalize tags to lowercase trimmed strings
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === "string") {
    tags = tags.split(",");
  }
  return tags
    .map(t => t.trim().toLowerCase())
    .filter(t => t.length > 0);
}

/**
 * Filter problems by difficulty
 * @param {Array} problems
 * @param {string|string[]} difficulty
 * @returns {Array}
 */
function filterByDifficulty(problems, difficulty) {
  if (!difficulty) return problems;
  const difficulties = Array.isArray(difficulty) ? difficulty : [difficulty];
  const normalized = difficulties.map(d => d.toLowerCase());
  return problems.filter(p => normalized.includes(p.difficulty.toLowerCase()));
}

/**
 * Filter problems by skill tags (case-insensitive)
 * @param {Array} problems
 * @param {string|string[]} skillTags
 * @returns {Array}
 */
function filterBySkillTags(problems, skillTags) {
  const normalizedTags = normalizeTags(skillTags);
  if (normalizedTags.length === 0) return problems;

  return problems.filter(problem => {
    if (!problem.tags || !Array.isArray(problem.tags)) return false;
    const problemTags = problem.tags.map(t => t.toLowerCase());
    // Problem must have all skill tags (AND semantics)
    return normalizedTags.every(tag => problemTags.includes(tag));
  });
}

